import { Effect, Stream, Chunk, pipe } from "effect";

interface User { readonly id: number; readonly name: string }

const fetchUser = (id: number): Effect.Effect<User, Error> =>
  id > 0
    ? Effect.succeed({ id, name: `user-${id}` })
    : Effect.fail(new Error(`invalid id ${id}`));

const ids: ReadonlyArray<number> = [1, 2, -3, 4];

const program: Effect.Effect<Chunk.Chunk<User>> = pipe(
  Stream.fromIterable(ids),
  Stream.mapEffect((id: number) => Effect.either(fetchUser(id))),
  Stream.filterMap((e) => (e._tag === "Right" ? { _tag: "Some", value: e.right } as const : { _tag: "None" } as const)),
  Stream.map((opt) => (opt._tag === "Some" ? opt.value : { id: 0, name: "" })),
  Stream.runCollect,
);

Effect.runPromise(program).then((c) => console.log(Chunk.toReadonlyArray(c)));
