import { Effect, Duration, Data, pipe } from "effect";

class TimeoutError extends Data.TaggedError("TimeoutError")<{ readonly url: string }> {}
class NetworkError extends Data.TaggedError("NetworkError")<{ readonly cause: unknown }> {}

const fetchJson = (url: string): Effect.Effect<unknown, NetworkError> =>
  Effect.tryPromise({
    try: () => fetch(url).then((r) => r.json() as Promise<unknown>),
    catch: (u) => new NetworkError({ cause: u }),
  });

const fetchWithTimeout = (url: string): Effect.Effect<unknown, TimeoutError | NetworkError> =>
  pipe(
    fetchJson(url),
    Effect.timeoutFail({
      duration: Duration.seconds(2),
      onTimeout: () => new TimeoutError({ url }),
    }),
  );

Effect.runPromise(fetchWithTimeout("https://example.com/api")).catch((e) => console.error(e));
