import { Effect, Duration, Option, pipe } from "effect";

const slow: Effect.Effect<number> = Effect.delay(Effect.succeed(42), Duration.millis(500));

// Effect.timeout returns Option<A>: Some on success, None if the deadline fired.
const bounded: Effect.Effect<Option.Option<number>> = pipe(
  slow,
  Effect.timeout(Duration.millis(100)),
  Effect.catchAll(() => Effect.succeed(Option.none<number>())),
  Effect.map((opt) => (Option.isOption(opt) ? opt : Option.some(opt as number))),
);

Effect.runPromise(bounded).then((res: Option.Option<number>) => {
  console.log(Option.isSome(res) ? `ok ${res.value}` : "timed out");
});
```

Effect.timeout wraps the result in Option<A> — a non-failing signal that simply says "didn't finish in time". Effect.timeoutFail goes further: it terminates the effect with an error value you construct, which flows into the typed E channel just like any other failure. Use timeoutFail when the deadline is a real failure mode (you want retries, catchTag, or an HTTP 504 response); use timeout when the caller can genuinely continue with no result.

