import { Effect, Duration, Data, pipe } from "effect";

class DeadlineExceeded extends Data.TaggedError("DeadlineExceeded")<{ readonly ms: number }> {}

const withDeadline = <A, E, R>(
  eff: Effect.Effect<A, E, R>,
  ms: number,
): Effect.Effect<A, E | DeadlineExceeded, R> =>
  pipe(
    eff,
    Effect.timeoutFail({
      duration: Duration.millis(ms),
      onTimeout: () => new DeadlineExceeded({ ms }),
    }),
  );

const job: Effect.Effect<string> = Effect.succeed("done");
const bounded = withDeadline(job, 500);
Effect.runPromise(bounded).then(console.log);
