import { Effect, Duration, pipe } from "effect";

const primary: Effect.Effect<string> = Effect.delay(Effect.succeed("primary"), Duration.millis(80));
const fallback: Effect.Effect<string> = Effect.delay(Effect.succeed("fallback"), Duration.millis(120));

// Effect.race interrupts the loser as soon as one side completes.
const winner: Effect.Effect<string> = Effect.race(primary, fallback);

Effect.runPromise(winner).then((s: string) => {
  console.log(s); // "primary"
});
```

When you call Effect.race(a, b), the runtime forks both a and b onto fibres and awaits the first to complete (success or failure). The moment one side settles, the loser receives an interrupt signal — any acquire/release scope it owns runs its finaliser, so there are no resource leaks. Race therefore composes cleanly with Effect.scoped and Effect.acquireRelease.

