import { Effect, Duration, Data, pipe } from "effect";

class AllDown extends Data.TaggedError("AllDown")<{ readonly urls: ReadonlyArray<string> }> {}

const ping = (url: string): Effect.Effect<string, AllDown> =>
  Math.random() > 0.3
    ? Effect.delay(Effect.succeed(url), Duration.millis(50 + Math.random() * 100))
    : Effect.fail(new AllDown({ urls: [url] }));

const firstHealthy = (urls: ReadonlyArray<string>): Effect.Effect<string, AllDown> => {
  if (urls.length === 0) return Effect.fail(new AllDown({ urls: [] }));
  const [head, ...tail] = urls;
  const effs: ReadonlyArray<Effect.Effect<string, AllDown>> = [ping(head), ...tail.map(ping)];
  return Effect.raceAll(effs);
};

Effect.runPromise(firstHealthy(["a", "b", "c"]))
  .then(console.log)
  .catch(console.error);
