import { Effect, pipe } from "effect";

const workUnit = (name: string): Effect.Effect<void> =>
  pipe(
    Effect.logInfo(`starting ${name}`),
    Effect.flatMap(() => Effect.logInfo(`finished ${name}`)),
  );

const traced: Effect.Effect<void> = pipe(
  Effect.gen(function* () {
    yield* workUnit("load");
    yield* workUnit("save");
