import { Effect, pipe } from "effect";

const decode = (raw: string): Effect.Effect<{ readonly n: number }> =>
  pipe(
    Effect.succeed({ n: Number.parseInt(raw, 10) }),
    Effect.withSpan("request.decode"),
  );

const handle = (raw: string): Effect.Effect<number> =>
  pipe(
    Effect.gen(function* () {
      const dec = yield* decode(raw);
      return dec.n * 2;
    }),
    // The outer span wraps the whole handler; decode's span nests automatically.
    Effect.withSpan("request.handle", { attributes: { raw } }),
  );

Effect.runPromise(handle("21")).then(console.log);
```

Effect.withSpan opens a span for the duration of the wrapped effect. The span is attached to the current fibre context, so any nested effect automatically becomes a child span — even across Effect.gen, Effect.flatMap, or forked fibres. When the wrapped effect succeeds or fails, the span is closed and the elapsed time is recorded. This gives you a tree of spans that mirrors your call graph with zero threading of context.

```typescript
import { Effect, pipe } from "effect";

interface Parsed { readonly userId: string }
interface Validated { readonly userId: string; readonly ok: true }
interface Response { readonly status: number }

const parse = (body: string): Effect.Effect<Parsed> =>
  pipe(Effect.succeed({ userId: body }), Effect.withSpan("http.parse"));

const validate = (p: Parsed): Effect.Effect<Validated> =>
  pipe(Effect.succeed({ ...p, ok: true as const }), Effect.withSpan("http.validate"));

const respond = (v: Validated): Effect.Effect<Response> =>
  pipe(Effect.succeed({ status: 200 }), Effect.withSpan("http.respond", { attributes: { userId: v.userId } }));

const handler = (body: string): Effect.Effect<Response> =>
  pipe(
    Effect.gen(function* () {
      const p = yield* parse(body);
      const v = yield* validate(p);
      return yield* respond(v);
    }),
    Effect.withSpan("http.handler"),
  );
