import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";
import * as RE from "fp-ts/ReaderEither";

interface Config { readonly minNameLength: number; readonly allowedDomains: ReadonlyArray<string> }
interface Input { readonly name: string; readonly email: string }
interface User { readonly name: string; readonly email: string }

const checkName = (i: Input): RE.ReaderEither<Config, string, Input> =>
  (cfg) =>
    i.name.length >= cfg.minNameLength
      ? E.right(i)
      : E.left(`name must be >= ${cfg.minNameLength}`);

const checkDomain = (i: Input): RE.ReaderEither<Config, string, Input> =>
  (cfg) =>
    cfg.allowedDomains.some((d) => i.email.endsWith(`@${d}`))
      ? E.right(i)
      : E.left(`domain not allowed`);

const register = (i: Input): RE.ReaderEither<Config, string, User> =>
  pipe(
    checkName(i),
    RE.chainW(checkDomain),
    RE.map(({ name, email }) => ({ name, email })),
  );

const cfg: Config = { minNameLength: 3, allowedDomains: ["example.com"] };
const result: E.Either<string, User> = register({ name: "Ada", email: "ada@example.com" })(cfg);
console.log(result);
