import { pipe } from "fp-ts/function";
import * as R from "fp-ts/Reader";

interface Env { readonly baseUrl: string; readonly version: number }

const buildPath = (route: string): R.Reader<Env, string> =>
  (env) => `${env.baseUrl}/v${env.version}${route}`;

const withQuery = (q: string) => (path: string): R.Reader<Env, string> =>
  () => `${path}?q=${encodeURIComponent(q)}`;

const program: R.Reader<Env, string> = pipe(
  buildPath("/search"),
  R.chain(withQuery("effect ts")),
);

const env: Env = { baseUrl: "https://api.example", version: 2 };
console.log(program(env)); // https://api.example/v2/search?q=effect%20ts
```

ReaderEither<R, E, A> is the product of Reader (an environment R threaded implicitly) and Either (a typed success A or failure E). Composing two ReaderEithers with RE.chain keeps the environment the same across the whole chain while short-circuiting on the first Left. RE.chainW widens E so each step can contribute its own error variant to a union. You only "run" the pipeline at the edge by applying the final Reader to the concrete environment — before that, it's just a value describing a computation.

