import * as RE from "fp-ts/ReaderEither";

interface CountryTable { readonly codes: ReadonlyArray<string> }
interface Address { readonly street: string; readonly country: string }

const validateCountry = (a: Address): RE.ReaderEither<CountryTable, string, Address> =>
  (tbl) => (tbl.codes.includes(a.country) ? E.right(a) : E.left(`unknown country ${a.country}`));

const normaliseStreet = (a: Address): RE.ReaderEither<CountryTable, string, Address> =>
  () => E.right({ ...a, street: a.street.trim().toUpperCase() });

const process = (a: Address): RE.ReaderEither<CountryTable, string, Address> =>
  pipe(validateCountry(a), RE.chainW(normaliseStreet));
