import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";
import * as RE from "fp-ts/ReaderEither";

interface Rules { readonly maxLen: number; readonly prefix: string }
type ValidationError =
  | { readonly _tag: "Empty" }
  | { readonly _tag: "TooLong"; readonly max: number }
  | { readonly _tag: "BadPrefix"; readonly want: string };

const nonEmpty = (s: string): RE.ReaderEither<Rules, ValidationError, string> =>
  () => (s.length > 0 ? E.right(s) : E.left({ _tag: "Empty" as const }));

const maxLen = (s: string): RE.ReaderEither<Rules, ValidationError, string> =>
  (r) => (s.length <= r.maxLen ? E.right(s) : E.left({ _tag: "TooLong" as const, max: r.maxLen }));

const startsWithPrefix = (s: string): RE.ReaderEither<Rules, ValidationError, string> =>
  (r) =>
    s.startsWith(r.prefix)
      ? E.right(s)
      : E.left({ _tag: "BadPrefix" as const, want: r.prefix });

const validate = (s: string): RE.ReaderEither<Rules, ValidationError, string> =>
  pipe(nonEmpty(s), RE.chainW(maxLen), RE.chainW(startsWithPrefix));

const rules: Rules = { maxLen: 10, prefix: "usr-" };
console.log(validate("usr-abc")(rules));
```

The refactor lifts `fullUrl` into `Reader<Env, string>` — a function from the environment to a result. Callers build up a `Reader` pipeline and only apply it to a concrete `Env` at the edge. No more passing `env` through every intermediate helper.

