import * as NEA from "fp-ts/NonEmptyArray";
import type { Semigroup } from "fp-ts/Semigroup";

// Semigroup for a NonEmptyArray of strings: simple concatenation.
const neaStringSemigroup: Semigroup<NEA.NonEmptyArray<string>> = {
  concat: (x, y) => NEA.concat(y)(x),
};

const errsA: NEA.NonEmptyArray<string> = ["name required"];
const errsB: NEA.NonEmptyArray<string> = ["email invalid", "age < 0"];

const combined: NEA.NonEmptyArray<string> = pipe(
  [errsA, errsB] as NEA.NonEmptyArray<NEA.NonEmptyArray<string>>,
  NEA.concatAll(neaStringSemigroup),
);

