A Semigroup<A> says "A has a way to combine two values into one". NonEmptyArray<E> is a natural error container because concatenating two non-empty lists is still non-empty. Pairing them with the applicative instance for Validation (Either-like but accumulating) lets you run all field checks and merge every Left into a combined NonEmptyArray<E>, instead of the default Either chain that stops on the first Left.

```typescript
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";
import * as NEA from "fp-ts/NonEmptyArray";
import { sequenceT } from "fp-ts/Apply";
import { getSemigroup } from "fp-ts/NonEmptyArray";

interface Form { readonly name: string; readonly age: number; readonly email: string }

const lift = <A>(check: E.Either<string, A>): E.Either<NEA.NonEmptyArray<string>, A> =>
  pipe(check, E.mapLeft((s) => [s] as NEA.NonEmptyArray<string>));

const checkName = (n: string) => n.length > 0 ? E.right(n) : E.left("name required");
const checkAge = (a: number) => a >= 0 ? E.right(a) : E.left("age must be >= 0");
const checkEmail = (e: string) => /@/.test(e) ? E.right(e) : E.left("email missing @");

const validate = (f: Form): E.Either<NEA.NonEmptyArray<string>, Form> => {
  const applicative = E.getApplicativeValidation(getSemigroup<string>());
  return pipe(
    sequenceT(applicative)(lift(checkName(f.name)), lift(checkAge(f.age)), lift(checkEmail(f.email))),
    E.map(([name, age, email]) => ({ name, age, email })),
  );
};
```

