  { id: "u1" },
  { name: "Ada" },
  { email: "ada@example.com" },
  { name: "Augusta" },
];

const merged: User = pipe(fragments, NEA.concatAll(userSemigroup));
console.log(merged); // { id: 'u1', name: 'Augusta', email: 'ada@example.com' }
