import { pipe } from "fp-ts/function";
import * as NEA from "fp-ts/NonEmptyArray";
import type { Semigroup } from "fp-ts/Semigroup";

const minSemi: Semigroup<number> = { concat: (x, y) => (x < y ? x : y) };
const maxSemi: Semigroup<number> = { concat: (x, y) => (x > y ? x : y) };

const prices: NEA.NonEmptyArray<number> = [9.99, 4.5, 7.25, 12.0, 5.75];

const minMax = (xs: NEA.NonEmptyArray<number>): readonly [number, number] => {
  const min = pipe(xs, NEA.concatAll(minSemi));
  const max = pipe(xs, NEA.concatAll(maxSemi));
  return [min, max];
};

const [lo, hi] = minMax(prices);
console.log(`min=${lo} max=${hi}`); // min=4.5 max=12
